quest_id',$request_id);			}								$result = $this->rpc_service->resultJSON();			// print_r($result);						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$return['valid'] = $result['valid'];							$return['status_code'] = $result['no'];							$return['message'] = $result['des'];						}					} else {						$return['status_code'] = $result['no'];						$return['message'] = $result['des'];					}				}			}					} else {			$return['valid'] = false;			$return['message'] = "Session expired";		}				echo json_encode($return);	}		function post_add_edit(){		$this->authentication->plainlayout();		$parameter = array();		$return = array();										$request_id = isset($_POST['request_id']) ? $_POST['request_id'] : '';		$request_no = isset($_POST['request_no']) ? $_POST['request_no'] : '';		$request_date = isset($_POST['request_date']) ? $_POST['request_date'] : '';		$info = isset($_POST['info']) ? $_POST['info'] : '';						$user_id = $this->session->userdata('user_id');				$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				if(count($_POST) > 0){			if($request_id){				$this->rpc_service->setSP("dbo.sp_request_assembly_edit");				$this->rpc_service->addField('request_id',$request_id);			} else {				$this->rpc_service->setSP("dbo.sp_request_assembly_add");			}						$this->rpc_service->addField('request_no',$request_no);			$this->rpc_service->addField('request_date',$request_date);			$this->rpc_service->addField('info',$info);									$result = $this->rpc_service->resultJSON();									$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$data = json_decode($result['data'],TRUE);							$request_id = $data['request_id'];														$return['valid'] = $result['valid'];							