dit");				$this->rpc_service->addField('request_detail_id',$request_detail_id);			} else {				$this->rpc_service->setSP("dbo.sp_request_assembly_detail_add");			}						$this->rpc_service->addField('request_id',$request_id);			$this->rpc_service->addField('item_id',$item_id);			$this->rpc_service->addField('request_item_id',$request_item_id);			$this->rpc_service->addField('quantity_request',$quantity_request);						$result = $this->rpc_service->resultJSON();						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){														$return['valid'] = $result['valid'];							$return['status_code'] = $result['no'];							$return['message'] = $result['des'];												}					} else {						$return['status_code'] = $result['no'];						$return['message'] = $result['des'];					}				}			}					} else {			$return['valid'] = false;			$return['message'] = "Session expired";		}				echo json_encode($return);	}				function delete_detail(){		$this->authentication->plainlayout();		$parameter = array();		$return = array();				$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				$request_detail_id = isset($_POST['request_detail_id']) ? $_POST['request_detail_id'] : '';		$user_id = $this->session->userdata('user_id');				if(count($_POST) > 0){						if($request_detail_id){				$this->rpc_service->setSP("dbo.sp_request_assembly_detail_delete");				$this->rpc_service->addField('request_detail_id',$request_detail_id);			}								$result = $this->rpc_service->resultJSON();			// print_r($result);						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$return['valid'] = $result['valid'];							$return['status_code'] = $result['no'];							$return['message'] = $result['des'];						}					} else 